import AnimateInView from "./AnimateInView"
import ProductCard from "./ProductCard"

const Product=()=>{
    return(
         <section id="products" className="bg-green-dark text-white relative overflow-hidden">
                  <div className="container mx-auto px-6 max-w-7xl">
                      <AnimateInView className="text-center max-w-3xl mx-auto mb-16" yOffset={30}>
                          <h2 className="text-white mb-4">
                              Всё лучшее от белорусских фермеров
                          </h2>
                          <p className="text-white/80 text-lg">
                              Более 17 фермеров каждый уикенд привозят свежую продукцию
                          </p>
                      </AnimateInView>
                      
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
                          {/* Применение AnimateInView с каскадным эффектом (разными задержками) */}
                          <AnimateInView delay={0.1}>
                              <ProductCard icon="🥩" title="Мясо и рыба" description="Говядина, свинина, баранина, птица, рыба. " />
                          </AnimateInView>
                          <AnimateInView delay={0.2}>
                              <ProductCard icon="🧀" title="Сыры" description="Козьи и коровьи: твёрдые, мягкие, с плесенью." />
                          </AnimateInView>
                          <AnimateInView delay={0.3}>
                              <ProductCard icon="🍞" title="Хлеб и выпечка" description="Хлеб на закваске, который пахнет детством и домашним уютом." />
                          </AnimateInView>
                          <AnimateInView delay={0.4}>
                              <ProductCard icon="🍯" title="Мясные деликатесы" description="Мясные деликатесы современного приготовления высокого качества." />
                          </AnimateInView>
                          <AnimateInView delay={0.4}>
                              <ProductCard icon="🍯" title="Мед и напитки" description="Натуральный мед, медовые напитки, домашний квас." />
                          </AnimateInView>
                            <AnimateInView delay={0.4}>
                              <ProductCard icon="🍯" title="Сладости" description="Зефир, моти, пряники, сырки, торты. Десерты без химии." />
                          </AnimateInView>
                           <AnimateInView delay={0.4}>
                              <ProductCard icon="🍯" title="Соусы и загатовки" description="Домашние соусы, чаи, варенья, специи, загатовки  " />
                          </AnimateInView>
                          <AnimateInView delay={0.4}>
                              <ProductCard icon="🍯" title="Овощи и зелень" description="Сезонные овощи и свежая зелень прямо с огорода" />
                          </AnimateInView>
                      </div>
                  </div>
              </section>
    )
}
export default Product;