import Image from 'next/image';

interface ProductCardProps {
  icon: string; // Эмодзи или путь к изображению
  title: string;
  description: string;
}

const ProductCard: React.FC<ProductCardProps> = ({ icon, title, description }) => {
  // Проверяем, является ли иконка путем к изображению (например, /images/cheese.png)
  const isImagePath = icon.startsWith('/');

  return (
    <div className="bg-white/5 backdrop-blur-sm rounded-lg p-7 text-center border border-white/10 hover:border-white/30 transition duration-300 hover:shadow-strong cursor-default">
      
      <div className="mb-4 inline-block">
        {isImagePath ? (
          // Если это изображение (для замены заглушки)
          <Image 
            src={icon} 
            alt={title} 
            width={56} 
            height={56} 
            className="mx-auto h-14 w-14 object-contain transition-all duration-500 hover:scale-110"
          />
        ) : (
          // Если это эмодзи
          <span className="text-6xl block transition-all duration-500 hover:scale-110">
            {icon}
          </span>
        )}
      </div>
      
      <h3 className="font-body text-xl font-semibold text-white mb-2">
        {title}
      </h3>
      <p className="text-sm text-white/70 leading-relaxed">
        {description}
      </p>
    </div>
  );
};

export default ProductCard;